    }

    public void processEmployeeData() {
        int salary = 5000;
        int bonus = 0;

        if (salary > 4000) {
            bonus = 1000;
        } else {
            bonus = 500;
        }

        int total = salary + bonus;
        System.out.println("Total salary: " + total);

        if (total > 5500) {
            System.out.println("High paid employee");
        } else {
            System.out.println("Regular employee");
        }

        System.out.println("Processing complete");
    }
}

class Employee {
    private String id;
    private String name;
    private int age;
    private String department;
    private double salary;

    public Employee(String id, String name, int age, String department, double salary) {
        this.id = id;
        this.name = name;
        this.age = age;
        this.department = department;
        this.salary = salary;
    }

    public String getId() {
        return id;
    }

    public String getName() {
        return name;
    }

    public int getAge() {
        return age;
    }

    public String getDepartment() {
        return department;
    }

    public double getSalary() {
        return salary;
    }
}
